#include <stdio.h>
#include <string.h>

int longestStringChain(char **words, int wordsSize) {
    int dp[wordsSize];
    for (int i = 0; i < wordsSize; i++) dp[i] = 1;
    for (int i = 0; i < wordsSize; i++) {
        for (int j = 0; j < i; j++) {
            if (strlen(words[i]) == strlen(words[j]) + 1) {
                int k = 0, l = 0;
                while (k < strlen(words[i])) {
                    if (l < strlen(words[j]) && words[i][k] == words[j][l]) l++;
                    k++;
                }
                if (l == strlen(words[j])) dp[i] = dp[i] > dp[j] + 1 ? dp[i] : dp[j] + 1;
            }
        }
    }
    int max = 0;
    for (int i = 0; i < wordsSize; i++) max = max > dp[i] ? max : dp[i];
    return max;
}

